async function loadUser() {
  try {
    const res = await fetch('/api/user');
    if (!res.ok) {
      throw new Error(`HTTP ${res.status}`);
    }
    return await res.json();
  } catch (err) {
    console.error('Erreur:', err);
    return null; // valeur par défaut
  }
}

